export interface Achievement {
    id: string;
    name: string;
    description: string;
    icon: string;
    category: string;
    points: number;
    condition: (player: unknown, stats: unknown) => boolean;
    hidden: boolean;
}

export interface AchievementProgress {
    unlocked: boolean;
    progress: number;
    maxProgress: number;
    unlockedAt: number | null;
}

export class AchievementSystem {
    private isInitialized: boolean = false;
    private achievements: Map<string, Achievement> = new Map();
    private unlockedAchievements: Set<string> = new Set();
    private achievementProgress: Map<string, AchievementProgress> = new Map();
    private achievementPoints: number = 0;

    constructor() {
        this.isInitialized = false;
        this.achievementPoints = 0;
    }

    async init(): Promise<void> {
        this.loadAchievementData();
        this.loadPlayerProgress();
        this.isInitialized = true;
        console.log('[AchievementSystem] 成就系统初始化完成');
    }

    private loadAchievementData(): void {
        this.registerAchievement({
            id: 'first_blood',
            name: '初次杀敌',
            description: '击败你的第一个敌人',
            icon: '🗡️',
            category: 'combat',
            points: 10,
            condition: (player: unknown, stats: unknown) => {
                const s = stats as { monstersKilled?: number };
                return (s?.monstersKilled || 0) >= 1;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'monster_hunter',
            name: '怪物猎人',
            description: '击败100个敌人',
            icon: '🎯',
            category: 'combat',
            points: 50,
            condition: (player: unknown, stats: unknown) => {
                const s = stats as { monstersKilled?: number };
                return (s?.monstersKilled || 0) >= 100;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'undefeated',
            name: '无敌战神',
            description: '连续赢得10场战斗',
            icon: '🏆',
            category: 'combat',
            points: 100,
            condition: (player: unknown, stats: unknown) => {
                const s = stats as { battlesWon?: number; battlesLost?: number };
                const winStreak = Math.min((s?.battlesWon || 0) - (s?.battlesLost || 0), s?.battlesWon || 0);
                return winStreak >= 10;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'first_equipment',
            name: '武装起来',
            description: '装备第一件物品',
            icon: '🛡️',
            category: 'equipment',
            points: 10,
            condition: (player: unknown) => {
                const p = player as { equipment?: Record<string, unknown> };
                if (!p?.equipment) return false;
                return Object.values(p.equipment).some(item => item !== null);
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'legendary_collector',
            name: '传说收藏家',
            description: '装备一件传说品质物品',
            icon: '⭐',
            category: 'equipment',
            points: 200,
            condition: (player: unknown) => {
                const p = player as { equipment?: Record<string, { rarity?: string } | null> };
                if (!p?.equipment) return false;
                return Object.values(p.equipment).some(item => item?.rarity === 'legendary');
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'explorer',
            name: '探索者',
            description: '发现5个地点',
            icon: '🗺️',
            category: 'exploration',
            points: 20,
            condition: (player: unknown) => {
                const p = player as { unlockedLocations?: string[] };
                return (p?.unlockedLocations?.length || 0) >= 5;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'world_traveler',
            name: '世界旅行者',
            description: '发现所有地点',
            icon: '🌍',
            category: 'exploration',
            points: 100,
            condition: (player: unknown) => {
                const p = player as { unlockedLocations?: string[] };
                return (p?.unlockedLocations?.length || 0) >= 8;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'quest_starter',
            name: '冒险开始',
            description: '完成第一个任务',
            icon: '📜',
            category: 'quest',
            points: 15,
            condition: (player: unknown, stats: unknown) => {
                const s = stats as { questsCompleted?: number };
                return (s?.questsCompleted || 0) >= 1;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'quest_master',
            name: '任务大师',
            description: '完成50个任务',
            icon: '🎖️',
            category: 'quest',
            points: 100,
            condition: (player: unknown, stats: unknown) => {
                const s = stats as { questsCompleted?: number };
                return (s?.questsCompleted || 0) >= 50;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'level_10',
            name: '初出茅庐',
            description: '达到10级',
            icon: '🌱',
            category: 'level',
            points: 20,
            condition: (player: unknown) => {
                const p = player as { level?: number };
                return (p?.level || 0) >= 10;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'level_50',
            name: '经验丰富',
            description: '达到50级',
            icon: '💪',
            category: 'level',
            points: 150,
            condition: (player: unknown) => {
                const p = player as { level?: number };
                return (p?.level || 0) >= 50;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'level_100',
            name: '传说等级',
            description: '达到100级',
            icon: '👑',
            category: 'level',
            points: 300,
            condition: (player: unknown) => {
                const p = player as { level?: number };
                return (p?.level || 0) >= 100;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'first_gold',
            name: '第一桶金',
            description: '获得1000金币',
            icon: '💰',
            category: 'gold',
            points: 10,
            condition: (player: unknown) => {
                const p = player as { gold?: number };
                return (p?.gold || 0) >= 1000;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'millionaire',
            name: '百万富翁',
            description: '获得1,000,000金币',
            icon: '💎',
            category: 'gold',
            points: 200,
            condition: (player: unknown) => {
                const p = player as { gold?: number };
                return (p?.gold || 0) >= 1000000;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'card_collector',
            name: '卡牌收藏家',
            description: '收集30张卡牌',
            icon: '🃏',
            category: 'card',
            points: 50,
            condition: (player: unknown) => {
                const p = player as { inventory?: { type?: string }[] };
                const cardCount = p?.inventory?.filter(item => item?.type === 'card').length || 0;
                return cardCount >= 30;
            },
            hidden: false
        });

        this.registerAchievement({
            id: 'secret_finding',
            name: '秘密发现者',
            description: '发现一个隐藏地点',
            icon: '🔮',
            category: 'secret',
            points: 150,
            condition: (player: unknown) => {
                const p = player as { unlockedLocations?: string[] };
                return p?.unlockedLocations?.some(loc => loc.includes('secret') || loc.includes('hidden')) || false;
            },
            hidden: true
        });
    }

    private registerAchievement(achievement: Achievement): void {
        this.achievements.set(achievement.id, achievement);

        if (!this.achievementProgress.has(achievement.id)) {
            this.achievementProgress.set(achievement.id, {
                unlocked: false,
                progress: 0,
                maxProgress: 1,
                unlockedAt: null
            });
        }
    }

    checkAchievements(): void {
        const win = window as unknown as { game?: { player?: unknown }; stateManager?: { get: (key: string) => unknown } };
        const player = win.game?.player;
        const stats = win.stateManager?.get('statistics');

        if (!player) return;

        for (const [id, achievement] of this.achievements) {
            if (this.unlockedAchievements.has(id)) continue;

            try {
                if (achievement.condition(player, stats)) {
                    this.unlockAchievement(id);
                }
            } catch (error) {
                console.error(`[AchievementSystem] Error checking achievement ${id}:`, error);
            }
        }
    }

    private unlockAchievement(id: string): void {
        const achievement = this.achievements.get(id);
        if (!achievement || this.unlockedAchievements.has(id)) return;

        this.unlockedAchievements.add(id);
        this.achievementPoints += achievement.points;

        const progress = this.achievementProgress.get(id);
        if (progress) {
            progress.unlocked = true;
            progress.unlockedAt = Date.now();
        }

        this.showAchievementUnlocked(achievement);
        this.saveProgress();

        console.log(`[AchievementSystem] 成就解锁: ${achievement.name}`);
    }

    private showAchievementUnlocked(achievement: Achievement): void {
        const notification = document.createElement('div');
        notification.className = 'achievement-notification';
        notification.innerHTML = `
            <div class="achievement-icon">${achievement.icon}</div>
            <div class="achievement-info">
                <div class="achievement-title">成就解锁！</div>
                <div class="achievement-name">${achievement.name}</div>
                <div class="achievement-points">+${achievement.points} 点</div>
            </div>
        `;

        document.body.appendChild(notification);

        const win = window as unknown as { audioSystem?: { playSound?: (sound: string) => void } };
        win.audioSystem?.playSound?.('achievement');

        setTimeout(() => {
            notification.classList.add('fade-out');
            setTimeout(() => notification.remove(), 500);
        }, 3000);
    }

    getAchievement(id: string): Achievement | undefined {
        return this.achievements.get(id);
    }

    getAllAchievements(category: string | null = null): Achievement[] {
        let achievements = Array.from(this.achievements.values());

        if (category) {
            achievements = achievements.filter(a => a.category === category);
        }

        return achievements;
    }

    isUnlocked(id: string): boolean {
        return this.unlockedAchievements.has(id);
    }

    getUnlockedAchievements(): Achievement[] {
        return Array.from(this.unlockedAchievements)
            .map(id => this.achievements.get(id))
            .filter((a): a is Achievement => a !== undefined);
    }

    getLockedAchievements(): Achievement[] {
        return Array.from(this.achievements.values())
            .filter(achievement => !this.unlockedAchievements.has(achievement.id));
    }

    getTotalPoints(): number {
        return Array.from(this.achievements.values())
            .reduce((sum, a) => sum + a.points, 0);
    }

    getUnlockedPoints(): number {
        return this.achievementPoints;
    }

    getCompletionRate(): string {
        const total = this.achievements.size;
        const unlocked = this.unlockedAchievements.size;
        return total > 0 ? ((unlocked / total) * 100).toFixed(1) : '0';
    }

    private loadPlayerProgress(): void {
        const saved = localStorage.getItem('tavern_achievements');
        if (saved) {
            try {
                const data = JSON.parse(saved);
                this.unlockedAchievements = new Set(data.unlocked || []);
                this.achievementPoints = data.points || 0;

                if (data.progress) {
                    for (const [id, progress] of Object.entries(data.progress as Record<string, AchievementProgress>)) {
                        this.achievementProgress.set(id, progress);
                    }
                }
            } catch (error) {
                console.error('[AchievementSystem] Failed to load achievement progress:', error);
            }
        }
    }

    private saveProgress(): void {
        const data: {
            unlocked: string[];
            points: number;
            progress: Record<string, AchievementProgress>;
        } = {
            unlocked: Array.from(this.unlockedAchievements),
            points: this.achievementPoints,
            progress: {}
        };

        for (const [id, progress] of this.achievementProgress) {
            data.progress[id] = progress;
        }

        localStorage.setItem('tavern_achievements', JSON.stringify(data));
    }

    resetProgress(): void {
        this.unlockedAchievements.clear();
        this.achievementPoints = 0;
        this.achievementProgress.clear();
        this.loadAchievementData();
        this.saveProgress();
    }
}

export default AchievementSystem;
